INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Compare single, double and closed circulatory systems.', 'Single (e.g. fish): blood passes through the heart once per circuit; gill -> body. Double (mammals): twice per circuit (pulmonary + systemic), maintaining higher pressures. Closed: blood remains within vessels (mammals); open (insects): haemolymph bathes tissues.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Describe a single cardiac cycle.', 'Atrial systole: atria contract, AV valves open, ventricles fill. Ventricular systole: AV valves close (lub), ventricles contract, SL valves open, blood ejected. Diastole: SL valves close (dub), all chambers relax, atria refill. Cycle ~0.8 s at 75 bpm.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Compare arteries, veins and capillaries.', 'Arteries: thick muscular wall, narrow lumen, elastic, carry oxygenated blood (except pulmonary) at high pressure. Veins: thin wall, wide lumen, valves prevent backflow at low pressure. Capillaries: one cell thick endothelium, narrow, large total SA -> exchange.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Why is water described as a polar molecule?', 'O is more electronegative than H, creating a partial negative charge on O and partial positives on H. Water molecules form hydrogen bonds, giving high specific heat capacity, latent heat of vaporisation, cohesion, and excellent solvent properties.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Distinguish saturated, monounsaturated and polyunsaturated fatty acids.', 'Saturated: no C=C, straight chain, solid (animal fats). Monounsaturated: one C=C; polyunsaturated: 2+ C=C, kinked chains -> oils, liquid. cis/trans isomerism affects health: trans fats raise LDL.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Compare HDL and LDL.', 'LDL (low-density): transports cholesterol from liver to tissues; high LDL contributes to atheromas. HDL (high-density): returns cholesterol from tissues to liver. A high HDL : LDL ratio is associated with reduced cardiovascular disease risk.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Describe the formation of an atheroma and its consequences.', 'Damage to endothelium -> inflammation; LDL and white blood cells accumulate in the artery wall, forming a fibrous plaque (atheroma). Lumen narrows; elasticity falls; BP rises; plaque rupture -> thrombosis -> heart attack or stroke.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'List CVD risk factors and how each contributes.', 'Genetics, age, gender. Modifiable: high BP, high LDL, smoking (CO reduces O2 capacity, nicotine raises BP), diet (saturated/trans fats, salt), inactivity, obesity, diabetes. Each damages endothelium or alters blood lipids.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Define correlation vs causation, and identify confounding variables.', 'Correlation: two variables vary together. Causation: one variable directly produces the change in the other. Confounding variables: a third factor that affects both (e.g. age, smoking). Studies must control these to identify true causation.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Compare cohort and case-control studies.', 'Cohort: a group is followed forward in time, recording outcomes (lung cancer in smokers vs non-smokers). Case-control: starts with cases (lung cancer patients) and controls, looks back at exposures (smoking). Cohort is stronger evidence but slower.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Describe the structure of haemoglobin and oxygen binding.', 'Quaternary protein: 4 polypeptide subunits (2 alpha, 2 beta), each with a haem group containing Fe2+ that binds one O2. Cooperative binding gives a sigmoidal dissociation curve.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Explain the Bohr effect.', 'Increased CO2 / H+ in active tissue lowers pH, reducing haemoglobin''s affinity for O2. The dissociation curve shifts right, so more O2 is unloaded where it is most needed.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Describe how cholesterol-lowering treatments work.', 'Statins inhibit HMG-CoA reductase -> less cholesterol synthesis in the liver. Anti-platelet drugs (aspirin) reduce clot risk. Antihypertensives (ACE inhibitors, beta blockers, diuretics) lower BP. Plant stanols competitively inhibit cholesterol absorption.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Define risk and probability and calculate from data.', 'Risk = probability of an event = number of events / total. Relative risk = exposure group risk / unexposed risk. e.g. if smokers'' risk = 0.2, non-smokers'' = 0.05, RR = 4 -> 4-fold higher risk.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Outline how lifestyle interventions reduce CVD risk.', 'Stop smoking, reduce saturated/trans fats and salt, increase fruit/veg/fibre, exercise regularly, maintain healthy BMI, moderate alcohol. These lower BP and LDL, improve insulin sensitivity, and reduce inflammation.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe the structure of DNA.', 'A nucleotide = phosphate + deoxyribose + base (A, T, C or G). Polynucleotide strands joined by phosphodiester bonds. Two antiparallel strands held by H-bonds: A=T (2), G≡C (3). Twisted into a right-handed double helix.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Compare DNA in eukaryotes vs prokaryotes.', 'Eukaryotic DNA: linear, in nucleus, wound around histones, has introns and exons. Prokaryotic DNA: circular, in cytoplasm (nucleoid), no histones, no introns. Plasmids may also be present.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Outline the genetic code.', 'Triplet, non-overlapping, degenerate, universal. Start codon AUG; three stop codons. With 4 bases x 3 positions = 64 codons coding 20 amino acids -> redundancy reduces effects of mutation.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe transcription and post-transcriptional modification.', 'RNA polymerase joins free RNA nucleotides to a template strand (U replaces T) -> pre-mRNA. Splicing removes introns; exons rejoin. 5'' cap and poly-A tail added. Mature mRNA exits via nuclear pore.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe translation in detail.', 'Small ribosomal subunit binds mRNA; tRNA carrying methionine binds AUG; large subunit completes ribosome. Next tRNA binds complementary codon; peptide bond forms. Ribosome translocates one codon. Continues until a stop codon -> polypeptide released.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe types of gene mutations and outcomes.', 'Substitution: silent / missense / nonsense. Insertion or deletion: frameshift -> all subsequent amino acids changed. Effect depends on protein function: e.g. sickle-cell anaemia (substitution Glu -> Val in beta-globin) and CF (delta F508 deletion).', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Outline cystic fibrosis at the molecular level.', 'Mutation in the CFTR gene (chr 7) — most commonly delta F508. CFTR is a chloride channel. Faulty channel -> thick mucus in airways, gut, reproductive system. Treatments target symptoms (physiotherapy, mucolytics) and the cause (CFTR modulators, gene therapy).', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe how cystic fibrosis is inherited.', 'Autosomal recessive: two cf alleles needed (one from each parent). Carriers (Cc) show no symptoms. Two carriers x: 1/4 affected, 1/2 carriers, 1/4 unaffected. Genetic counselling and prenatal testing available.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe phospholipid bilayer structure.', 'Two layers of phospholipids: hydrophilic phosphate heads point outward (towards aqueous); hydrophobic fatty acid tails point inward. The membrane is fluid; cholesterol regulates fluidity; proteins are embedded as channels, carriers and receptors.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Compare diffusion, facilitated diffusion, osmosis and active transport.', 'Diffusion: passive, lipid-soluble or gases, no protein. Facilitated diffusion: passive via channel/carrier proteins. Osmosis: passive water movement down water-potential gradient. Active transport: against gradient, ATP-driven by carrier proteins.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe how Na+ and Cl- normally cross airway epithelium and how CF disrupts this.', 'Normal: Cl- ions move out through CFTR channels into mucus; Na+ follows; water follows osmotically -> thin watery mucus. CF: faulty CFTR -> Cl- cannot leave; Na+ moves into cell instead; water leaves mucus -> thick sticky mucus.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe the structure of the lungs and gas exchange.', 'Trachea -> bronchi -> bronchioles -> alveoli (~300 million; ~70 m^2). Alveoli: thin squamous epithelium, surrounded by capillaries (also one cell thick), surfactant lining, ventilated by breathing -> O2 diffuses to blood, CO2 diffuses out.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Outline the role of cilia and goblet cells.', 'Goblet cells secrete mucus that traps pathogens and dust. Ciliated epithelial cells beat to move mucus up to the throat where it is swallowed (mucociliary escalator). Smoking paralyses cilia -> chronic cough.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe pre-natal genetic testing for CF (CVS and amniocentesis).', 'CVS (10-13 weeks): biopsy of chorionic villi, faster, slightly higher miscarriage risk (~1%). Amniocentesis (15-20 weeks): sample of amniotic fluid containing fetal cells; lower miscarriage risk (~0.5%) but later. PCR / genetic analysis of CFTR gene.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Outline ethical considerations of genetic testing.', 'Benefits: informed reproductive choices, treatment planning. Issues: psychological impact, insurance discrimination, privacy, potential for selective termination, parental disagreements, mis-diagnosis. Pre-test counselling is essential.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Describe the eukaryotic cell cycle.', 'G1: cell growth, organelle replication. S: DNA replication. G2: further growth, error check. M: mitosis (PMAT). Cytokinesis. Checkpoints (G1/S, G2/M, spindle) prevent damaged cells progressing.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Outline the four stages of mitosis.', 'Prophase: chromosomes condense (sister chromatids visible), nuclear envelope breaks down, centrosomes move to poles. Metaphase: chromosomes line up on equator. Anaphase: spindle pulls sister chromatids to poles. Telophase: nuclear envelopes reform.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Compare mitosis and meiosis.', 'Mitosis: 1 division, 2 diploid identical daughter cells, growth/repair. Meiosis: 2 divisions, 4 haploid genetically distinct gametes, with independent assortment and crossing over. Source of variation -> evolution.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Describe two sources of genetic variation in meiosis.', 'Independent assortment: homologous chromosomes line up randomly in metaphase I (and sister chromatids in metaphase II). Crossing over: in prophase I, non-sister chromatids exchange DNA at chiasmata, forming new allele combinations.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Define totipotent, pluripotent, multipotent and unipotent.', 'Totipotent: any cell type incl. extra-embryonic (e.g. zygote). Pluripotent: any embryonic cell type (e.g. embryonic stem cells). Multipotent: limited types (e.g. haematopoietic stem cells). Unipotent: one type (e.g. cardiac muscle progenitor).', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Outline how stem cells differentiate.', 'Differentiation results from selective gene expression. Specific TFs activate cell-type-specific genes; epigenetic changes (DNA methylation, histone modification) silence others. Position-dependent signals (morphogens) and the cells'' microenvironment guide specialisation.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Outline benefits and ethical issues of using human embryonic stem cells.', 'Benefits: pluripotent -> potential regenerative therapies (Parkinson''s, spinal injury). Ethics: destruction of embryos; iPS cells offer an alternative with fewer concerns. Strict regulation (HFEA in the UK).', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Describe how genes and environment interact.', 'Genotype sets potential; phenotype is the result of gene expression + environment. e.g. height (genetic potential limited by nutrition); MZ twins'' methylomes drift over time; many traits are polygenic and multifactorial.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Compare continuous and discontinuous variation.', 'Continuous: range of values (height, mass), polygenic and influenced by environment, normal distribution. Discontinuous: distinct categories (blood group), usually one or few genes, environment little effect; bar chart distribution.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Describe cell signalling and gene expression.', 'Signal molecule (e.g. hormone) binds a receptor -> transduction (often a phosphorylation cascade) -> activates TFs that bind DNA, switching specific genes on/off. Allows tissue-specific responses.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Outline mammalian fertilisation.', 'Sperm acrosome reaction: enzymes digest zona pellucida. Sperm membrane fuses with oocyte. Cortical reaction prevents polyspermy. Sperm nucleus enters; meiosis II completes; haploid pronuclei fuse -> diploid zygote. Cleavage starts.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Compare mitochondrial DNA inheritance to nuclear DNA.', 'Mitochondrial DNA is inherited only from the mother (sperm mitochondria are destroyed in zygote). Useful in tracing maternal lineage; mutations linked to several rare diseases.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Outline how the placenta supports the fetus.', 'Maternal and fetal blood are separated by chorionic villi (large SA, thin walls). Glucose, amino acids, O2 and antibodies cross to the fetus; CO2, urea, hormones cross from fetus to mother. Placenta also secretes hCG, oestrogen, progesterone.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Describe positional information and gradients in development.', 'Concentrations of morphogens (e.g. retinoic acid, Hox transcription factors) form gradients along the embryo, instructing cells about their position and which genes to express. Different thresholds give different fates.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'How are chromosomes packaged in the nucleus?', 'DNA wraps around 8 histone proteins to form a nucleosome (~146 bp). Nucleosomes coil into a 30 nm fibre and fold into chromatin. Heterochromatin (densely packed) silences genes; euchromatin (open) is transcribed.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Outline the eight taxonomic ranks and three domains.', 'Domain, Kingdom, Phylum, Class, Order, Family, Genus, Species. Three domains (Woese): Bacteria, Archaea, Eukarya — based on rRNA sequences, membrane lipids, and genome organisation.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Define a species and describe two ways to define it.', 'Phylogenetic: shared evolutionary lineage on a tree of life. Biological: members can interbreed to produce fertile offspring. Issues: hybrid sterility (mules), asexual species, ring species. Modern molecular comparisons supplement morphology.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'How are molecular methods used to classify organisms?', 'Direct DNA / amino acid sequence comparison gives quantitative similarity. Closer relatives share more conserved sequences. Confirms or revises classifications based on morphology and reveals evolutionary relationships hidden by convergent evolution.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Define biodiversity at three levels.', 'Habitat: number of habitats in an area. Species: richness (count) and evenness (relative abundance). Genetic: variety of alleles within a population. All three vary independently and matter for ecosystem stability.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Calculate Simpson''s index of diversity.', 'D = 1 - sum (n / N)^2, where n = individuals of each species and N = total. D ranges 0-1; higher = more diverse and stable. Sensitive to both richness and evenness.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Define endemism and give an example.', 'A species found only in a single restricted area. e.g. lemurs (Madagascar), Galapagos finches. Endemic species are vulnerable to extinction because their entire range can be affected by a single disturbance.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Describe the structure of plant cell walls.', 'Cellulose microfibrils (beta-1,4 glucose) crosslinked by hemicellulose and embedded in pectin. Lignin adds strength to xylem and sclerenchyma. Plasmodesmata link cells. The wall provides support, shape and tensile strength against turgor pressure.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Compare xylem and phloem.', 'Xylem: dead, lignified tubes carrying water/minerals from root to leaves; mass flow driven by transpiration tension. Phloem: living sieve tubes with companion cells, transports assimilates (sucrose) from sources to sinks by mass flow.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Outline the cohesion-tension theory of water transport.', 'Water evaporates from spongy mesophyll into air spaces and out via stomata. Tension is created in xylem; H-bonds keep water as a continuous column. Adhesion to xylem walls aids capillary action.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Describe plant defences against herbivores and pathogens.', 'Physical: thorns, waxy cuticle, hairs (trichomes), thick cell walls. Chemical: tannins (deter feeding), alkaloids (caffeine, nicotine — toxic to insects), terpenoids, antimicrobial proteins. Some defences are induced (jasmonic acid pathway).', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'How are plants used in medicine? (Drug discovery)', 'Examples: aspirin from willow bark salicylates, taxol from yew (cancer), digitalis from foxglove (heart). Bioprospecting screens biodiverse regions; loss of biodiversity means losing potential drugs.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Describe testing of new drugs (William Withering / clinical trials).', 'Withering used systematic patient observation to determine the correct dose of digitalis. Modern trials: pre-clinical (cells, animals), Phase I (safety in healthy volunteers), II (efficacy), III (large randomised trial vs placebo or current treatment), IV (post-market surveillance).', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Compare in situ and ex situ conservation.', 'In situ: protect species in natural habitat (national parks, reserves) — preserves ecological interactions but vulnerable to disasters. Ex situ: zoos, seed banks, botanical gardens — controlled but smaller gene pool, risk of inbreeding.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Describe a seed bank.', 'Stores dried, low-T seeds (e.g. Millennium Seed Bank, Kew) ex situ. Long-term storage preserves genetic diversity, crop wild relatives, and species at risk of extinction. Limitations: only seed-bearing plants, viability declines, periodic germination tests required.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Outline how zoos contribute to species conservation.', 'Captive breeding programmes (e.g. Arabian oryx, giant panda); coordinated international stud books prevent inbreeding; reintroduction projects; education and research. Critics raise concerns about welfare and habitat loss being the root problem.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Write the photosynthesis equation and identify oxidation/reduction.', '6CO2 + 6H2O -> C6H12O6 + 6O2 (sunlight). CO2 is reduced (gains H/electrons) to glucose. H2O is oxidised to O2 in photolysis at PSII.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Outline the light-dependent reactions.', 'Photolysis at PSII: 2H2O -> 4H+ + 4e- + O2. Excited e- pass down ETC, pumping H+ into thylakoid lumen -> ATP via chemiosmosis. NADP+ + H+ + 2e- -> NADPH. Cyclic photophosphorylation produces only ATP.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Describe the Calvin cycle.', 'CO2 + RuBP -> 2 GP (catalysed by RuBisCO). GP reduced to TP using ATP and NADPH. Some TP forms hexose; most regenerates RuBP using ATP. Six turns yield one glucose.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Describe how light, CO2 and temperature affect photosynthesis.', 'Each can be a limiting factor when in shortest supply. Low light: rate limited by photolysis. Low CO2: rate limited by Calvin cycle. Below optimum T: enzymes slow; above ~30 °C: RuBisCO denatures, stomata close.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Define an ecosystem and give an example food chain.', 'Ecosystem = community of organisms + their abiotic environment. Energy enters via producers (NPP), passes to herbivores (primary consumers), to carnivores (secondary), and to top predators. ~10% transfer between levels typical.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Define and calculate net primary productivity (NPP).', 'GPP = total chemical energy fixed by producers per area per time. NPP = GPP - R (respiration). Units: kJ m^-2 yr^-1. NPP is energy available to next trophic level.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Describe the carbon cycle.', 'Photosynthesis fixes CO2 into organic compounds; respiration, combustion and decomposition return CO2. Carbon stored in biomass, soil, oceans (HCO3-), fossil fuels. Anthropogenic CO2 (fossil fuel burning, deforestation) increases atmospheric levels.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'List evidence for climate change.', 'Direct: ice core CO2 / temperature records, atmospheric CO2 measurements (Mauna Loa), satellite data, sea-level rise, glacier retreat. Indirect: dendrochronology, pollen analysis, isotope ratios in foraminifera. Multiple independent lines converge on warming.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Explain how rising temperatures affect species distribution.', 'Species shift poleward and upward in altitude as temperatures rise; phenological mismatches (flowering vs pollinators) occur; range contractions if no migration possible (e.g. mountain-top species). Loss of habitat and mismatched timing reduce reproductive success.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Describe primary succession from bare rock.', 'Pioneer species (e.g. lichens) colonise bare rock, weather it and add organic matter. Mosses follow, then small plants, grasses, shrubs and finally woodland (climax). Each stage modifies the abiotic conditions for the next.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Compare deflected and secondary succession.', 'Secondary: starts on existing soil after disturbance (e.g. fire); succession proceeds as for primary but faster. Deflected: human activity (mowing, grazing) holds the community at an earlier seral stage (heathland, chalk grassland) — often biodiverse.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'State Hardy-Weinberg principle and equations.', 'Allele frequencies stay constant across generations if: large population, no migration, no mutation, no selection, random mating. p + q = 1; p^2 + 2pq + q^2 = 1.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Describe natural selection in peppered moths and antibiotic resistance.', 'Peppered moth: dark form favoured during industrial pollution (camouflage on sooty trees); light form returns after Clean Air Act. Antibiotic resistance: random mutations in bacteria; resistant variants survive antibiotic treatment and reproduce.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Compare allopatric and sympatric speciation.', 'Allopatric: geographical isolation -> divergent selection / drift -> reproductive isolation. Sympatric: arises within a population without a physical barrier (polyploidy in plants, behavioural / temporal isolation).', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'How can we mitigate climate change biologically?', 'Reduce CO2 emissions (fossil fuel substitution, energy efficiency); reforestation and afforestation; rewetting peatlands; protect oceans (blue carbon); reduce deforestation; carbon capture and storage; soil management. Both supply-side and demand-side action needed.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Compare types of pathogens and give one example each.', 'Bacteria: prokaryote, peptidoglycan wall (e.g. TB Mycobacterium tuberculosis). Virus: nucleic acid + capsid, hijacks host (HIV). Fungi: eukaryote, hyphae (athlete''s foot Trichophyton). Protoctist: eukaryote (Plasmodium - malaria).', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe non-specific (innate) defences.', 'Skin barrier; mucous membranes; lysozyme in tears/saliva; gastric acid; ciliated epithelia; phagocytosis (neutrophils, macrophages); inflammation (histamine, vasodilation); fever (raised T inhibits pathogens). Fast but non-specific.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe phagocytosis step-by-step.', 'Phagocyte chemotaxes towards pathogen, recognises by surface receptors, engulfs by endocytosis -> phagosome. Lysosomes fuse with phagosome -> phagolysosome; lysozyme digests pathogen. Antigens displayed on MHC for T-cell activation.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Compare T helper, T killer and B cells.', 'T helper: bind APCs, release cytokines that activate other cells. T killer: directly kill infected/cancer cells (perforin, granzymes). B cells: differentiate into plasma cells (antibodies) or memory cells once selected by their specific antigen.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe antibody structure and four functions.', 'Y-shape, two heavy + two light chains, constant + variable regions, two antigen-binding sites. Functions: agglutination, opsonisation (mark for phagocytosis), neutralisation of toxins, activation of complement.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Compare primary and secondary immune responses.', 'Primary: slow lag, low antibody peak, may show symptoms. Memory cells form. Secondary: rapid (hours), high antibody peak, often asymptomatic. Forms the basis of long-term immunity.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe vaccination and herd immunity.', 'Vaccines contain weakened/inactivated pathogens or antigens, triggering primary response and memory cells without disease. If many in a population are immune, the pathogen cannot spread (herd immunity), protecting unvaccinated individuals.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Distinguish active, passive, natural and artificial immunity.', 'Active: own antibodies / memory (long-term). Passive: received antibodies (short-term). Natural: through life (infection / breast milk). Artificial: vaccines (active) or antibody injection (passive, e.g. anti-tetanus).', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'How do antibiotics work?', 'Bactericidal: kill bacteria (penicillin disrupts peptidoglycan synthesis -> weak walls -> lysis). Bacteriostatic: prevent growth (tetracyclines block 70S ribosomes -> halt protein synthesis). Selective toxicity: target features absent in human cells.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'How does antibiotic resistance evolve?', 'Random mutation gives resistance (e.g. beta-lactamase, modified penicillin-binding proteins). Antibiotics select for resistant strains; resistance genes spread via plasmid conjugation (horizontal transfer). Misuse and incomplete courses accelerate this.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe how time of death is estimated.', 'Algor mortis: ~1.5 °C drop per hour (first 12 h). Rigor mortis: stiffness from ~2 h, peak at 12 h, fades by 36 h. Hypostasis (livor): blood pooling, fixed by ~12 h. Insect succession (entomology). Stomach contents.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Outline DNA profiling using STRs.', 'Extract DNA, amplify short tandem repeat (STR) regions by PCR, separate fragments by gel/capillary electrophoresis. Each individual has a near-unique STR profile -> banding pattern. Used in identification, paternity, forensics.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Outline polymerase chain reaction (PCR).', 'Cycles: 95 °C denature -> ~55 °C anneal primers -> 72 °C extend with Taq polymerase. Each cycle doubles DNA -> 2^n copies after n cycles. Used in cloning, sequencing and DNA profiling.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe how decomposers contribute to nutrient cycling.', 'Saprobionts (fungi, bacteria) secrete extracellular enzymes onto dead matter; soluble products absorbed by diffusion. Detritivores fragment material. Resulting NH4+ enters the nitrogen cycle; CO2 returns to atmosphere via respiration.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Outline forensic uses of mtDNA.', 'mtDNA is inherited maternally and present in many copies per cell -> retrievable from old / degraded samples (bone, hair shaft) where nuclear DNA is unrecoverable. Compared with maternal relatives to identify remains (e.g. Romanovs).', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'List the four stages of aerobic respiration with location.', 'Glycolysis (cytoplasm), link reaction (matrix), Krebs cycle (matrix), oxidative phosphorylation (inner mitochondrial membrane / cristae).', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Outline glycolysis.', 'Glucose phosphorylated using 2 ATP -> hexose bisphosphate -> 2 triose phosphate. Each TP oxidised to pyruvate; net 2 ATP and 2 NADH per glucose. Anaerobic; in cytoplasm.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe the link reaction and Krebs cycle.', 'Link: 2 pyruvate -> 2 acetyl-CoA, 2 NADH and 2 CO2. Krebs (x2): each acetyl-CoA + 4C -> 6C; decarboxylation/dehydrogenation give 2 CO2, 3 NADH, 1 FADH2 and 1 ATP per turn (per glucose: 4 CO2, 6 NADH, 2 FADH2, 2 ATP).', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Explain oxidative phosphorylation by chemiosmosis.', 'NADH/FADH2 deliver e- to ETC on inner membrane. Electrons pass between carriers, pumping H+ into intermembrane space. H+ flows back through ATP synthase -> ATP. O2 final acceptor: O2 + 4H+ + 4e- -> 2H2O.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Compare lactate and ethanol fermentation.', 'Animals: pyruvate + NADH -> lactate + NAD+; reversible (lactate cleared in liver -> oxygen debt). Yeast/plants: pyruvate -> ethanal + CO2 -> ethanol + NAD+; irreversible. Both regenerate NAD+ to allow glycolysis to continue.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Compare slow- and fast-twitch muscle fibres.', 'Slow-twitch (Type I): aerobic, many mitochondria, lots of myoglobin, fatigue-resistant (postural muscles, marathon). Fast-twitch (Type II): anaerobic glycolysis, large glycogen and phosphocreatine stores, fatigue quickly (sprinting, weightlifting).', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe the structure of a sarcomere.', 'Region between two Z-lines. Contains overlapping thin actin and thick myosin filaments. I-band: actin only. A-band: full length of myosin. H-zone: myosin only (no actin). M-line: middle of sarcomere. Sarcomere shortens during contraction.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Outline the sliding filament theory.', 'AP arrives at NMJ -> Ca2+ released from sarcoplasmic reticulum -> Ca2+ binds troponin, moving tropomyosin to expose actin binding sites. Myosin heads bind actin -> power stroke (ADP/Pi released). New ATP binds, head detaches; ATP -> ADP+Pi resets.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe how heart rate is controlled.', 'SAN sets pace -> wave of depolarisation across atria -> AVN delays -> Bundle of His -> Purkyne fibres -> ventricles contract from apex up. Medulla regulates rate via sympathetic (accelerator) and parasympathetic (vagus) nerves; baroreceptors and chemoreceptors feed back.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'How does exercise affect ventilation?', 'CO2 produced in respiration lowers blood pH; chemoreceptors in aortic / carotid bodies detect this and signal medulla -> increases breathing rate and depth. Stretch receptors in lungs prevent over-inflation. After exercise, debt repaid by elevated breathing.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Define VO2 max and how it adapts to training.', 'Maximum rate of O2 uptake during intense exercise (mL kg^-1 min^-1). Reflects cardiovascular and respiratory efficiency. Aerobic training raises VO2 max via increased stroke volume, capillary density, mitochondria and myoglobin in muscle.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe role of the kidneys in osmoregulation.', 'Ultrafiltration in glomerulus; selective reabsorption in PCT; loop of Henle establishes a salt gradient in the medulla; ADH-controlled water reabsorption in collecting duct. Maintains constant blood water potential during exercise / dehydration.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Outline thermoregulation during exercise.', 'Increased respiration produces heat. Hypothalamus detects rise; vasodilation of skin arterioles, sweating (evaporative cooling), reduced metabolic heat. After exercise: shivering or vasoconstriction may follow if body T overshoots.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe how performance-enhancing drugs work and ethical issues.', 'Anabolic steroids: mimic testosterone -> increased muscle synthesis; risks include heart damage and infertility. EPO: boosts red blood cells -> O2 carriage; risk of clots. Stimulants: mask fatigue. Ethics: unfair advantage, health risk, role-model effect, legality.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe the keyhole / arthroscopic surgery for sports injury.', 'A small incision allows a fibre-optic camera and instruments into a joint. Cartilage tears are trimmed or repaired; ACL reconstruction uses graft tissue. Less tissue trauma -> faster recovery than open surgery, though possible complications (infection, stiffness).', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe the structure of a typical neurone.', 'Cell body (with nucleus), dendrites (receive signals), axon (conducts AP), and axon terminals (release neurotransmitter). Axon may be myelinated by Schwann cells (PNS) or oligodendrocytes (CNS), with nodes of Ranvier.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Distinguish CNS and PNS, somatic and autonomic, sympathetic and parasympathetic.', 'CNS = brain + spinal cord. PNS: sensory + motor neurones. Somatic: voluntary skeletal muscle. Autonomic: involuntary smooth/cardiac muscle/glands. Sympathetic: fight/flight; parasympathetic: rest/digest.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Explain the resting potential.', 'Na+/K+ pump moves 3 Na+ out / 2 K+ in per ATP. K+ leaks out via leak channels, leaving inside ~-70 mV relative to outside. Maintained by ATP and selective membrane permeability.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Sketch and label an action potential.', 'Stimulus -> threshold (-55 mV) -> voltage-gated Na+ channels open (depolarisation to +40 mV). Na+ channels close, K+ channels open (repolarisation). Hyperpolarisation; Na+/K+ pump restores resting potential.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Why does myelination speed transmission?', 'Myelin (Schwann/oligodendrocyte) is electrically insulating. Action potentials only occur at unmyelinated nodes of Ranvier; the impulse "jumps" between nodes (saltatory conduction), much faster than continuous conduction.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe synaptic transmission at a cholinergic synapse.', 'AP arrives -> Ca2+ channels open, Ca2+ enters -> vesicles fuse with membrane and release ACh. ACh diffuses across cleft, binds postsynaptic receptors, opens Na+ channels. Acetylcholinesterase hydrolyses ACh; choline recycled.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe excitatory and inhibitory postsynaptic potentials.', 'EPSP: depolarising (Na+ entry) — moves potential towards threshold. IPSP: hyperpolarising (Cl- entry or K+ exit) — moves it away. Summation of EPSPs and IPSPs determines whether the postsynaptic neurone fires.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe the major regions of the human brain and their functions.', 'Cerebrum: voluntary action, learning, memory. Cerebellum: balance, coordination. Hypothalamus: homeostasis, thermoregulation. Pituitary: hormones. Medulla: heart and breathing centres.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Outline how the eye detects light.', 'Light passes cornea, pupil, lens (focuses), vitreous humour, hits retina. Rods (rhodopsin, peripheral, dim light) and cones (3 types, fovea, colour) generate AP -> bipolar cells -> ganglion cells -> optic nerve. Image processed in visual cortex.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Compare rods and cones.', 'Rods: high sensitivity (many to one bipolar -> retinal convergence); monochromatic; rhodopsin; concentrated outside fovea. Cones: low sensitivity, high acuity (1:1 to bipolar); iodopsin (3 colour types); concentrated in fovea.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Outline learning and types of memory.', 'Sensory -> short-term -> long-term (consolidation). Habituation: decreased response to a repeated harmless stimulus (sea-slug Aplysia). Classical and operant conditioning. Memories stored across synapses; LTP strengthens connections.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe how drugs affect synapses (e.g. nicotine, MDMA, L-DOPA).', 'Nicotine: agonist of nicotinic ACh receptors -> stimulation; reward via dopamine. MDMA: floods synapses with serotonin (release + reuptake inhibition). L-DOPA: precursor of dopamine, crosses BBB to relieve Parkinson''s symptoms.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe the symptoms and cause of Parkinson''s disease.', 'Loss of dopaminergic neurones in the substantia nigra. Symptoms: tremor, rigidity, bradykinesia, postural instability. Treatments: L-DOPA, dopamine agonists, MAO-B inhibitors, deep brain stimulation. Causes: idiopathic, genetic factors, environmental.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Outline the imaging techniques: CT, MRI, fMRI, PET.', 'CT: X-ray slices -> structural images. MRI: magnetic field aligns nuclei -> high-resolution structural images, no ionising radiation. fMRI: detects blood-O2 changes (BOLD signal) -> activity. PET: radiolabelled tracers -> functional metabolism.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Compare nature and nurture in shaping the brain.', 'Genes provide the basic neural framework (e.g. innate reflexes). Environment shapes synaptic connections, particularly in critical periods (e.g. visual deprivation in kittens). Both interact: brain plasticity allows learning throughout life.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP1: investigating effect of temperature on enzyme activity (amylase).', 'Use buffered amylase + starch at varying T (water baths). At intervals, sample on a tile with iodine -> note when iodine remains yellow (starch fully digested). Rate = 1/time. Optimum ~37 °C; activity falls sharply above as enzymes denature.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP2: cell fractionation.', 'Homogenise tissue in cold (slows enzymes), isotonic (prevents osmotic damage), buffered solution. Filter, then centrifuge at increasing speeds: pellets in order — nuclei -> chloroplasts -> mitochondria -> lysosomes -> ER -> ribosomes.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP3: investigating osmosis in plant tissue.', 'Cut equal-mass potato cylinders. Place in solutions of varied [sucrose]. After fixed time, blot, reweigh. % change in mass plotted against [sucrose]. Where mass change = 0, the potato''s water potential equals that of the surrounding solution.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP4: caffeine on Daphnia heart rate.', 'Place a Daphnia on a slide with pond water; locate heart under low power. Count beats over 10 s. Repeat with varied [caffeine]; allow acclimation. Plot rate vs concentration. Ethics: minimise distress.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP5: membrane permeability of beetroot at varied T.', 'Cut equal cylinders, rinse off leaked pigment. Place in distilled water at varied T (0-80 °C). Measure absorbance of leaked betacyanin in colorimeter (~470 nm). Higher absorbance -> more disrupted membrane.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP7: rate of water loss from a leaf.', 'Use a potometer or weighed leaves under controlled conditions. Vary humidity / wind / light. Monitor mass loss / bubble movement over time. Plot rate against IV; control all other factors.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP8: antimicrobial properties of plants.', 'Test extracts of garlic, mint, etc. on bacterial lawn (aseptic technique near a Bunsen). Place soaked discs onto agar. Incubate <25 °C. Measure zone of inhibition (diameter or area). Larger zone = greater antimicrobial activity.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP9: photosynthesis rate using Elodea.', 'Submerge pondweed in NaHCO3 solution (CO2 source). Vary light intensity (lamp distance) or wavelength (filters). Count bubbles per minute or use a gas syringe. Plot rate vs intensity. Control T, [CO2], pH.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP10: respiration rate using a respirometer.', 'Place germinating peas in a sealed tube with KOH (CO2 absorber); manometer fluid level moves as O2 consumed. Use thermostatically controlled bath. Control: glass beads. Calculate V(O2) per unit time per gram.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP11: effect of exercise on ventilation.', 'Measure breathing rate and depth at rest. Exercise (steady cycle / step) for 3-5 min; measure during recovery. Plot ventilation rate vs time. Use a peak-flow meter or spirometer for tidal volume. Control fitness level and rest period.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP12: plant tropism investigation.', 'Grow seedlings (e.g. cress) in different light conditions: unilateral light, dark, all-around light. Measure curvature of stems and roots. Positive phototropism in shoots; negative phototropism in roots. Control: T, water, type of seed.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP13: investigating genetic variation in a population.', 'Choose a continuously varying trait (height, hand span). Sample 30+ individuals; record measurements. Plot a histogram and calculate mean and SD. Continuous data tend to be normally distributed (polygenic + environmental influences).', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP14: estimating biodiversity using sampling techniques.', 'Random sampling: random coordinates with quadrats. Systematic: line/belt transect. Calculate species richness and Simpson''s index of diversity D = 1 - sum(n/N)^2. Use mark-release-recapture for mobile organisms.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP15: DNA extraction from a plant (onion).', 'Mash onion in salt + detergent (lyses membranes). Filter. Add cold ethanol gently to top -> DNA precipitates as a white "candy floss" at the interface. Collect with a glass rod.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'How is a result evaluated for accuracy and reliability?', 'Accuracy: closeness to true value (compare with literature / reference). Reliability: consistency on repetition (look at SD or range; repeat 5+ times). Consider random and systematic errors; identify limitations and improvements.', 15, 'alevel');
